{"path": "/tmp/sv-871aeebc8f7746869d2b1812b188eb91/Components/Catalog/ProductCard.razor", "file_text": "
<div class="card h-100 product-card @(Product.InStock ? "" : "border-secondary")"
     @onclick="HandleCardClick"
     role="button">
    <div class="card-img-top bg-light d-flex align-items-center justify-content-center"
         style="height: 180px;"
         role="img"
         aria-label="@Product.Name">
        <span class="text-muted">@Product.Name</span>
    </div>
    <div class="card-body d-flex flex-column">
        <h5 class="card-title">@Product.Name</h5>
        <p class="card-text fs-5 fw-bold text-primary">@Product.Price.ToString("C")</p>
        <p class="card-text">
            <span class="text-warning">@GetStarRating(Product.Rating)</span>
        </p>
        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }
        <button class="btn @(Product.InStock ? "btn-primary" : "btn-secondary") mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private async Task HandleCardClick()
    {
        await OnSelected.InvokeAsync(Product);
    }

    private async Task HandleAddToCart()
    {
        if (Product.InStock)
        {
            await OnAddToCart.InvokeAsync(Product);
        }
    }

    private static string GetStarRating(double rating)
    {
        int filled = (int)Math.Round(rating);
        int empty = 5 - filled;
        return new string('★', filled) + new string('☆', empty);
    }
}
"}

